namespace Application.Features.Command;

/// <summary>
/// Applies synced form templates from the Admin API into the local customer database.
/// </summary>
public class FormTemplateSyncCommandHandler(IApplicationDbContext context)
    : IRequestHandler<FormTemplateSyncCommand, Result>
{
    /// <summary>
    /// Upserts all forms, fields, and roles from the sync payload.
    /// </summary>
    /// <param name="request">The sync payload containing form templates from Admin.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns><see cref="Result.Success()"/> when all forms are persisted; otherwise a server error.</returns>
    public async Task<Result> Handle(FormTemplateSyncCommand request, CancellationToken cancellationToken)
    {
        try
        {
            var existingForms = context.FormTemplates
                .Include(x => x.Fields)
                .Include(x => x.Roles)
                .ToList();

            var existingFormsById = existingForms.ToDictionary(x => x.Id);
            var requestModelIds = request.Model.Select(x => x.Id).ToHashSet();

            foreach (var c in existingForms)
            {
                if (!requestModelIds.Contains(c.Id))
                    c.IsActive = false;
            }

            var orderedModels = request.Model
                .OrderBy(x => x.ParentFormId != null)
                .ToList();

            foreach (var c in orderedModels)
            {
                if (c.ParentFormId.HasValue)
                {
                    bool parentExists = existingFormsById.ContainsKey(c.ParentFormId.Value)
                                        || requestModelIds.Contains(c.ParentFormId.Value);

                    if (!parentExists)
                        c.ParentFormId = null;
                }

                if (!existingFormsById.TryGetValue(c.Id, out var form))
                {
                    form = c.Adapt<FormTemplate>();
                    form.Fields.Clear();
                    form.Roles.Clear();

                    await context.FormTemplates.AddAsync(form, cancellationToken);
                    existingFormsById[form.Id] = form;
                }
                else
                {
                    form.Description = c.Description;
                    form.Name = c.Name;
                    form.IsActive = c.IsActive;
                    form.Link = c.Link;
                    form.LinkText = c.LinkText;
                    form.NO = c.NO;
                    form.CategoryId = c.CategoryId;
                    form.Files = c.Files;
                    form.Type = c.Type;
                    form.LastRevisedDate = c.LastRevisedDate;
                    form.Code = c.Code;
                    form.ParentFormId = c.ParentFormId;
                    form.OrginalId = c.OrginalId;
                    form.ProjectName = c.ProjectName;
                }

                Update(form, c);
            }

            await context.SaveChangesAsync(cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private void Update(FormTemplate form, CustomerAllFormTemplateDto dto)
    {
        var dtoRoleIds = dto.Roles.ToHashSet();

        foreach (var role in form.Roles.ToList())
        {
            if (!dtoRoleIds.Contains(role.RoleId))
                context.FormRoles.Remove(role);
        }

        var formRoleIds = form.Roles.Select(x => x.RoleId).ToHashSet();
        foreach (var roleId in dto.Roles)
        {
            if (!formRoleIds.Contains(roleId))
                form.Roles.Add(new FormRole { RoleId = roleId });
        }

        var fieldsById = form.Fields.ToDictionary(x => x.Id);

        foreach (var field in form.Fields)
            field.IsActive = false;

        var orderedFields = dto.Fields.OrderBy(x => x.ParentFieldId).ToList();
        foreach (var c in orderedFields)
        {
            if (!fieldsById.TryGetValue(c.Id, out var formField))
            {
                formField = new FormField();
                form.Fields.Add(formField);
            }

            if (c.ParentFieldId.HasValue)
                c.ParentFieldId = c.ParentFieldId;

            if (!formField.Locked)
                c.Adapt(formField);

            fieldsById[formField.Id] = formField;
        }

        foreach (var field in form.Fields)
        {
            if (field.ParentFieldId.HasValue)
                field.ParentField = fieldsById[field.ParentFieldId.Value];
        }
    }
}

namespace Application.Features.Command;

/// <summary>
/// Propagates the base form template (metadata, roles, and fields) to all customer copies
/// linked via <see cref="FormTemplate.OrginalId"/>.
/// </summary>
/// <remarks>
/// <strong>Execution Flow:</strong>
/// <list type="number">
/// <item>Loads the base form and verifies it belongs to base data (<c>CustomerId</c> is null).</item>
/// <item>Finds customer forms where <c>OrginalId</c> equals the base form and <c>CustomerId</c> is in the selected list.</item>
/// <item>For each customer copy, synchronizes template properties, roles, and fields from the base form.</item>
/// <item>For <see cref="FormType.PermitNew"/> roots, also synchronizes all permit step child forms.</item>
/// <item>Remaps conditional and group field relationships using <c>OrginalId</c> as the stable key.</item>
/// <item>Returns the number of updated customer root forms.</item>
/// </list>
/// </remarks>
public class FormTemplatePropagateToCustomersCommandHandler(IApplicationDbContext context)
    : IRequestHandler<FormTemplatePropagateToCustomersCommand, Result<FormTemplatePropagateToCustomersCommandResult>>
{
    /// <summary>
    /// Applies base form changes to every customer form derived from the specified base template.
    /// </summary>
    /// <param name="request">The command containing the base form identifier.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns>
    /// A result whose <see cref="FormTemplatePropagateToCustomersCommandResult.UpdatedCount"/>
    /// contains the number of customer forms updated, or a domain/server error on failure.
    /// </returns>
    public async Task<Result<FormTemplatePropagateToCustomersCommandResult>> Handle(
        FormTemplatePropagateToCustomersCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var baseForm = await context.FormTemplates
                .Include(x => x.Roles)
                .Include(x => x.Fields)
                .FirstOrDefaultAsync(x => x.Id == request.FormId, cancellationToken);

            if (baseForm is null)
                return FormErrors.FormNotFound;

            if (baseForm.CustomerId.HasValue)
                return FormErrors.NotBaseForm;

            var customerIdSet = request.CustomerIds
                .Where(x => x > 0)
                .Distinct()
                .ToHashSet();

            if (customerIdSet.Count == 0)
                return FormErrors.NoCustomerCopyFound;

            var customerForms = await context.FormTemplates
                .Include(x => x.Roles)
                .Include(x => x.Fields)
                .Where(x => x.OrginalId == request.FormId
                            && x.CustomerId.HasValue
                            && customerIdSet.Contains(x.CustomerId.Value))
                .ToListAsync(cancellationToken);

            if (customerForms.Count == 0)
                return FormErrors.NoCustomerCopyFound;

            var baseChildren = new List<FormTemplate>();
            Dictionary<(int ParentFormId, int? CustomerId), List<FormTemplate>>? customerChildrenLookup = null;

            if (baseForm.Type == FormType.PermitNew)
            {
                baseChildren = await context.FormTemplates
                    .Include(x => x.Roles)
                    .Include(x => x.Fields)
                    .Where(x => x.ParentFormId == baseForm.Id && !x.CustomerId.HasValue)
                    .ToListAsync(cancellationToken);

                if (baseChildren.Count > 0)
                {
                    var customerRootIds = customerForms.Select(x => x.Id).ToHashSet();
                    var allCustomerChildren = await context.FormTemplates
                        .Include(x => x.Roles)
                        .Include(x => x.Fields)
                        .Where(x => x.ParentFormId.HasValue
                                    && customerRootIds.Contains(x.ParentFormId.Value))
                        .ToListAsync(cancellationToken);

                    customerChildrenLookup = allCustomerChildren
                        .GroupBy(x => (x.ParentFormId!.Value, x.CustomerId))
                        .ToDictionary(g => g.Key, g => g.ToList());
                }
            }

            var remapTargets = new List<(FormTemplate Base, FormTemplate Customer)>();

            foreach (var customerForm in customerForms)
            {
                SyncFormFromBase(baseForm, customerForm);
                remapTargets.Add((baseForm, customerForm));

                if (baseForm.Type == FormType.PermitNew && baseChildren.Count > 0)
                {
                    var customerChildren = customerChildrenLookup!.GetValueOrDefault(
                        (customerForm.Id, customerForm.CustomerId),
                        []);

                    SyncPermitChildrenFromBase(
                        customerForm,
                        baseChildren,
                        customerChildren,
                        remapTargets);
                }
            }

            await context.SaveChangesAsync(cancellationToken);

            foreach (var (base, customer) in remapTargets)
                RemapFieldRelationships(base, customer);

            await context.SaveChangesAsync(cancellationToken);

            return Result<FormTemplatePropagateToCustomersCommandResult>.Success(
                new FormTemplatePropagateToCustomersCommandResult(customerForms.Count));
        }
        catch (Exception ex)
        {
            Log.Error($"PropagateBaseFormToCustomers: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private void SyncFormFromBase(FormTemplate baseForm, FormTemplate customerForm)
    {
        CopyTemplateProperties(baseForm, customerForm);
        SyncRoles(baseForm, customerForm);

        var baseFields = baseForm.Fields
            .OrderBy(x => x.NO)
            .ThenBy(x => x.Id)
            .ToList();

        var baseFieldIds = baseFields.Select(x => x.Id).ToHashSet();
        var customerFieldsByOrginalId = customerForm.Fields
            .Where(x => x.OrginalId > 0)
            .GroupBy(x => x.OrginalId)
            .ToDictionary(g => g.Key, g => g.First());

        foreach (var baseField in baseFields)
        {
            if (!customerFieldsByOrginalId.TryGetValue(baseField.Id, out var customerField))
            {
                customerField = new FormField
                {
                    FormId = customerForm.Id,
                    OrginalId = baseField.Id,
                };
                customerForm.Fields.Add(customerField);
                context.FormFields.Add(customerField);
                customerFieldsByOrginalId[baseField.Id] = customerField;
            }

            CopyFieldProperties(baseField, customerField);
        }

        foreach (var customerField in customerForm.Fields.ToList())
        {
            if (customerField.OrginalId <= 0)
                continue;

            if (!baseFieldIds.Contains(customerField.OrginalId))
                RemoveFieldWithGroupChildren(customerForm, customerField);
        }
    }

    private void SyncPermitChildrenFromBase(
        FormTemplate customerRoot,
        List<FormTemplate> baseChildren,
        List<FormTemplate> customerChildren,
        List<(FormTemplate Base, FormTemplate Customer)> remapTargets)
    {
        var baseChildIds = baseChildren.Select(x => x.Id).ToHashSet();
        var customerChildrenByOrginalId = customerChildren
            .Where(x => x.OrginalId > 0)
            .GroupBy(x => x.OrginalId)
            .ToDictionary(g => g.Key, g => g.First());

        foreach (var baseChild in baseChildren)
        {
            if (!customerChildrenByOrginalId.TryGetValue(baseChild.Id, out var customerChild))
            {
                customerChild = CloneChildFormForCustomer(baseChild, customerRoot);
                customerChildren.Add(customerChild);
                customerChildrenByOrginalId[baseChild.Id] = customerChild;
            }
            else
            {
                customerChild.IsActive = true;
                customerChild.ParentFormId = customerRoot.Id;
                SyncFormFromBase(baseChild, customerChild);
            }

            remapTargets.Add((baseChild, customerChild));
        }

        foreach (var customerChild in customerChildren)
        {
            if (customerChild.OrginalId <= 0)
                continue;

            if (!baseChildIds.Contains(customerChild.OrginalId))
                customerChild.IsActive = false;
        }
    }

    private FormTemplate CloneChildFormForCustomer(FormTemplate baseChild, FormTemplate customerRoot)
    {
        var clone = new FormTemplate();
        CopyTemplateProperties(baseChild, clone);
        clone.Type = baseChild.Type;
        clone.OrginalId = baseChild.Id;
        clone.CustomerId = customerRoot.CustomerId;
        clone.ParentFormId = customerRoot.Id;
        clone.IsActive = true;

        foreach (var role in baseChild.Roles)
            clone.Roles.Add(new FormRole { RoleId = role.RoleId });

        var baseFields = baseChild.Fields.ToList();
        var baseFieldsById = baseFields.ToDictionary(x => x.Id);

        foreach (var field in baseFields)
        {
            if (field.ParentFieldId.HasValue
                && baseFieldsById.TryGetValue(field.ParentFieldId.Value, out var parentField))
                field.ParentField = parentField;

            if (field.GroupId.HasValue
                && baseFieldsById.TryGetValue(field.GroupId.Value, out var groupField))
                field.GroupParent = groupField;
        }

        foreach (var field in baseFields)
        {
            var newField = new FormField
            {
                FormId = 0,
                OrginalId = field.Id,
            };
            CopyFieldProperties(field, newField);
            clone.Fields.Add(newField);
            context.FormFields.Add(newField);
        }

        context.FormTemplates.Add(clone);
        return clone;
    }

    private static void RemapFieldRelationships(FormTemplate baseForm, FormTemplate customerForm)
    {
        var baseFields = baseForm.Fields
            .OrderBy(x => x.NO)
            .ThenBy(x => x.Id)
            .ToList();

        var fieldMap = customerForm.Fields
            .Where(x => x.OrginalId > 0)
            .ToDictionary(x => x.OrginalId, x => x);

        foreach (var baseField in baseFields)
        {
            if (!fieldMap.TryGetValue(baseField.Id, out var customerField))
                continue;

            customerField.ParentFieldId = null;
            customerField.GroupId = null;

            if (baseField.ParentFieldId.HasValue
                && fieldMap.TryGetValue(baseField.ParentFieldId.Value, out var parentField))
            {
                customerField.ParentFieldId = parentField.Id;
            }

            if (baseField.GroupId.HasValue
                && fieldMap.TryGetValue(baseField.GroupId.Value, out var groupField))
            {
                customerField.GroupId = groupField.Id;
            }
        }
    }

    private static void CopyTemplateProperties(FormTemplate source, FormTemplate target)
    {
        target.Name = source.Name;
        target.Description = source.Description;
        target.Code = source.Code;
        target.ProjectName = source.ProjectName;
        target.LastRevisedDate = source.LastRevisedDate;
        target.Link = source.Link;
        target.LinkText = source.LinkText;
        target.CategoryId = source.CategoryId;
        target.Type = source.Type;
        target.NO = source.NO;
        target.Files = source.Files.ToList();
    }

    private void SyncRoles(FormTemplate source, FormTemplate target)
    {
        var sourceRoleIds = source.Roles.Select(x => x.RoleId).ToHashSet();
        var targetRoleIds = target.Roles.Select(x => x.RoleId).ToHashSet();

        foreach (var role in target.Roles.ToList())
        {
            if (!sourceRoleIds.Contains(role.RoleId))
                context.FormRoles.Remove(role);
        }

        foreach (var roleId in sourceRoleIds)
        {
            if (!targetRoleIds.Contains(roleId))
                target.Roles.Add(new FormRole { RoleId = roleId, FormId = target.Id });
        }
    }

    private static void CopyFieldProperties(FormField source, FormField target)
    {
        target.Name = source.Name;
        target.Description = source.Description;
        target.CalculateCount = source.CalculateCount;
        target.Lines = source.Lines;
        target.DefaultValue = source.DefaultValue;
        target.NO = source.NO;
        target.IsActive = source.IsActive;
        target.Force = source.Force;
        target.Level = source.Level;
        target.IsSpecial = source.IsSpecial;
        target.ParentValue = source.ParentValue;
        target.Type = source.Type;
        target.Options = source.Options.ToList();
    }

    private void RemoveFieldWithGroupChildren(FormTemplate customerForm, FormField field)
    {
        if (field.Type == FormFieldType.Group)
        {
            foreach (var child in customerForm.Fields.Where(x => x.GroupId == field.Id).ToList())
                context.FormFields.Remove(child);
        }

        context.FormFields.Remove(field);
    }
}

