/// <summary>
/// Handles the execution of the <see cref="CustomerFormsQuery"/>.
/// </summary>
public class CustomerFormsQueryHandler(IApplicationDbContext context)
    : IRequestHandler<CustomerFormsQuery, Result<CustomerFormsQueryResult>>
{
    /// <summary>
    /// Fetches all active forms for a customer and maps their associated fields.
    /// </summary>
    /// <param name="request">The query containing the customer ID.</param>
    /// <param name="cancellationToken">The cancellation token.</param>
    /// <returns>A successful result containing mapped form and field DTOs, or a server error.</returns>
    /// <remarks>
    /// Execution Flow:
    /// <list type="bullet">
    /// <item><description>Fetch all active <c>FormTemplates</c> for the given customer, including their Roles.</description></item>
    /// <item><description>Fetch all <c>FormFields</c> for those forms in a separate query (avoids Cartesian explosion).</description></item>
    /// <item><description>Group fields by <c>FormId</c> and map each form and its fields to DTOs.</description></item>
    /// </list>
    /// </remarks>
    public async Task<Result<CustomerFormsQueryResult>> Handle(
        CustomerFormsQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var forms = await context.FormTemplates
                .Where(x => x.CustomerId == request.CustomerId)
                .Where(x => x.IsActive)
                .Include(x => x.Roles)
                .AsNoTracking()
                .ToListAsync(cancellationToken);

            if (forms.Count == 0)
                return Result<CustomerFormsQueryResult>.Success(new CustomerFormsQueryResult([]));

            var formIds = forms.Select(x => x.Id).ToList();
            var fieldsByFormId = (await context.FormFields
                    //.Where(x => x.IsActive)
                    .Where(x => formIds.Contains(x.FormId))
                    .AsNoTracking()
                    .ToListAsync(cancellationToken))
                .GroupBy(x => x.FormId)
                .ToDictionary(g => g.Key, g => g.ToList());

            var dto = new List<CustomerAllFormTemplateDto>(forms.Count);

            foreach (var form in forms)
            {
                form.Fields = fieldsByFormId.GetValueOrDefault(form.Id) ?? [];

                var formDto = form.Adapt<CustomerAllFormTemplateDto>();
                formDto.Fields = form.Fields.Adapt<List<CustomerAllFormFieldDto>>();
                dto.Add(formDto);
            }

            return Result<CustomerFormsQueryResult>.Success(new CustomerFormsQueryResult(dto));
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

