namespace Infrastructure.Services;

/// <summary>
/// Periodically pulls data from the Admin API into the Customer database.
/// </summary>
public class SyncBackgroundService : BackgroundService
{
    private readonly IServiceScopeFactory _scopeFactory;
    private readonly ILogger<SyncBackgroundService> _logger;
    private readonly SyncOption _syncOptions;

    /// <summary>
    /// Initializes a new instance of the <see cref="SyncBackgroundService"/> class.
    /// </summary>
    public SyncBackgroundService(
        IServiceScopeFactory scopeFactory,
        ILogger<SyncBackgroundService> logger,
        IOptions<SyncOption> syncOptions)
    {
        _scopeFactory = scopeFactory;
        _logger = logger;
        _syncOptions = syncOptions.Value;
    }

    /// <inheritdoc />
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        _logger.LogInformation(
            "Sync Background Service started. Initial delay: {InitialDelay} min, interval: {Interval} min.",
            _syncOptions.InitialDelayMinutes,
            _syncOptions.IntervalMinutes);

        if (_syncOptions.InitialDelayMinutes > 0)
        {
            try
            {
                await Task.Delay(TimeSpan.FromMinutes(_syncOptions.InitialDelayMinutes), stoppingToken);
            }
            catch (OperationCanceledException)
            {
                _logger.LogInformation("Sync Background Service was canceled during initial delay.");
                return;
            }
        }

        while (!stoppingToken.IsCancellationRequested)
        {
            await RunSyncOnceAsync(stoppingToken);

            try
            {
                await Task.Delay(TimeSpan.FromMinutes(_syncOptions.IntervalMinutes), stoppingToken);
            }
            catch (OperationCanceledException)
            {
                _logger.LogInformation("Sync Background Service was canceled during delay.");
                break;
            }
        }

        _logger.LogInformation("Sync Background Service stopped.");
    }

    private async Task RunSyncOnceAsync(CancellationToken stoppingToken)
    {
        try
        {
            using var scope = _scopeFactory.CreateScope();
            var syncService = scope.ServiceProvider.GetRequiredService<ISyncService>();
            _logger.LogInformation("Starting sync at {Time}", DateTimeOffset.Now);
            var result = await syncService.Sync(stoppingToken);

            if (!string.IsNullOrEmpty(result))
                _logger.LogWarning("Sync completed with errors: {Errors}", result);
            else
                _logger.LogInformation("Sync completed successfully.");
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "An error occurred during sync. Continuing to retry after delay.");
        }
    }
}

