    private async Task<bool> SyncFiles(HttpClient httpClient, CancellationToken cancellationToken)
    {
        try
        {
            FormTemplateFilesQuery query = new();
            var res = await _sender.Send(query, cancellationToken);

            if (!res.IsSuccess)
            {
                AddError("خطا در خواندن لیست فایل‌ها");
                return false;
            }

            var reportPath = _options.Value.ReportPath;
            if (!Directory.Exists(reportPath))
                Directory.CreateDirectory(reportPath);

            var fileNames = res.Value.Result;
            if (fileNames.Count == 0)
                return true;

            var syncOptions = _syncOptions.Value;
            var parallelism = syncOptions.FileDownloadParallelism;
            using var gate = new SemaphoreSlim(parallelism, parallelism);

            int downloaded = 0;
            int skipped = 0;

            var tasks = fileNames.Select(async fileName =>
            {
                await gate.WaitAsync(cancellationToken);
                try
                {
                    var fileUrl = $"{_options.Value.ReportUrl}/{fileName}";
                    var filePath = Path.Combine(reportPath, fileName);

                    var parentDir = Path.GetDirectoryName(filePath);
                    if (!string.IsNullOrEmpty(parentDir) && !Directory.Exists(parentDir))
                        Directory.CreateDirectory(parentDir);

                    if (syncOptions.SkipUnchangedFiles
                        && await ShouldSkipFileDownloadAsync(httpClient, fileUrl, filePath, cancellationToken))
                    {
                        Interlocked.Increment(ref skipped);
                        return;
                    }

                    using var response = await httpClient.GetAsync(
                        fileUrl,
                        HttpCompletionOption.ResponseHeadersRead,
                        cancellationToken);

                    if (!response.IsSuccessStatusCode)
                    {
                        AddError($"خطا در بارگیری فایل {fileName}: کد وضعیت {response.StatusCode}");
                        return;
                    }

                    await using var fileStream = new FileStream(filePath, FileMode.Create, FileAccess.Write, FileShare.None);
                    await response.Content.CopyToAsync(fileStream, cancellationToken);
                    Interlocked.Increment(ref downloaded);
                }
                catch (Exception ex) when (ex is not OperationCanceledException)
                {
                    AddError($"خطا در دانلود یا ذخیره فایل {fileName}: {ex.Message}");
                }
                finally
                {
                    gate.Release();
                }
            });

            await Task.WhenAll(tasks);

            _logger.LogInformation(
                "File sync finished. Downloaded: {Downloaded}, skipped unchanged: {Skipped}, total listed: {Total}.",
                downloaded,
                skipped,
                fileNames.Count);

            return true;
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            AddError($"خطای غیرمنتظره در همگام‌سازی فایل‌ها: {ex.Message}");
            return false;
        }
    }

    private static async Task<bool> ShouldSkipFileDownloadAsync(
        HttpClient httpClient,
        string fileUrl,
        string filePath,
        CancellationToken cancellationToken)
    {
        if (!File.Exists(filePath))
            return false;

        var localLength = new FileInfo(filePath).Length;

        using var headRequest = new HttpRequestMessage(HttpMethod.Head, fileUrl);
        using var headResponse = await httpClient.SendAsync(headRequest, cancellationToken);

        if (!headResponse.IsSuccessStatusCode)
            return false;

        var remoteLength = headResponse.Content.Headers.ContentLength;
        return remoteLength.HasValue && remoteLength.Value == localLength;
    }

}

